    best_val = 10**18
    for dx, dy in moves:
        nx, ny = sx + dx, sy + dy
        if not legal(nx, ny):
            continue
        d = (nx - cx) * (nx - cx) + (ny - cy) * (ny - cy)
        if d < best_val:
            best_val = d
            best_move = (dx, dy)
    return [int(best_move[0]), int(best_move[1])]
